import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const AdGrid = ({ pageNumber = 1 }) => {
  const [squares, setSquares] = useState([]);
  const navigate = useNavigate();

  // 🎯 CALCULATE SQUARE NUMBERS FOR THIS PAGE
  const startSquare = (pageNumber - 1) * 200 + 1;
  const endSquare = pageNumber * 200;
useEffect(() => {
  // TEMPORARY: Create mock purchases for testing all pages
  const createMockPurchases = () => {
    const mockPurchases = {};
    
    // Create some mock occupied squares on each page for testing
    for (let page = 1; page <= 10; page++) {
      const pageStart = (page - 1) * 200 + 1;
      
      // Mark a few squares as occupied on each page
      for (let i = 0; i < 5; i++) {
        const squareNum = pageStart + (i * 40); // Spread them out
        mockPurchases[squareNum] = {
          status: 'active',
          businessName: `Test Business ${squareNum}`,
          logoData: '/logo.PNG',
          adText: `Test ad for square ${squareNum}`,
          dealLink: 'https://example.com',
          endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        };
      }
    }
    
    return mockPurchases;
  };

  const purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
  
  // If no purchases exist, create mock data for testing
  if (Object.keys(purchases).length === 0) {
    const mockData = createMockPurchases();
    localStorage.setItem('squarePurchases', JSON.stringify(mockData));
  }

  // Continue with your existing logic...
  const actualPurchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
  
  const initialSquares = Array.from({ length: 200 }, (_, i) => {
    const squareNumber = startSquare + i;
    const purchase = actualPurchases[squareNumber];
    // ... rest of your existing logic
  });
  
  setSquares(initialSquares);
}, [pageNumber, startSquare]);
  useEffect(() => {
    // Load purchases from localStorage
    const purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
    
    const initialSquares = Array.from({ length: 200 }, (_, i) => {
      // 🎯 USE CORRECT SQUARE NUMBER BASED ON PAGE
      const squareNumber = startSquare + i;
      const purchase = purchases[squareNumber];
      
      if (purchase && purchase.status === 'active') {
        const endDate = new Date(purchase.endDate);
        const today = new Date();
        
        if (today < endDate) {
          return {
            id: squareNumber,
            isAvailable: false,
            businessName: purchase.businessName,
            logoData: purchase.logoData,
            adText: purchase.adText,
            dealLink: purchase.dealLink,
            endDate: purchase.endDate
          };
        }
      }
      
      return {
        id: squareNumber,
        isAvailable: true,
        price: '£1/day'
      };
    });
    
    setSquares(initialSquares);
  }, [pageNumber, startSquare]); // 🎯 ADD DEPENDENCIES

  const handleSquareClick = (square) => {
    if (square.isAvailable) {
      // 🎯 USE REACT ROUTER NAVIGATION INSTEAD OF WINDOW.LOCATION
      navigate('/purchase', { 
        state: { 
          squareNumber: square.id,
          pageNumber: pageNumber 
        } 
      });
    } else {
      window.open(square.dealLink, '_blank');
    }
  };

  return (
    <div className="grid-container">
      {/* 🎯 ADD PAGE INFO WITH CORRECT NUMBERING */}
      <div className="page-info">
        <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
        <p>
          {squares.filter(square => !square.isAvailable).length}/200 squares occupied
        </p>
      </div>
      
      <div className="squares-grid">
        {squares.map(square => (
          <div
            key={square.id}
            className="square"
            onClick={() => handleSquareClick(square)}
            title={!square.isAvailable ? `${square.businessName}\nClick to visit deal` : 'Click to purchase this square'}
          >
            {square.isAvailable ? (
              <>
                <div className="square-text">BUY THIS SQUARE</div>
                <div className="square-price">{square.price}</div>
                {/* 🎯 SHOWS CORRECT SQUARE NUMBER */}
                <div className="square-number">#{square.id}</div>
              </>
            ) : (
              <img 
                src={square.logoData || '/logo.PNG'} 
                alt={square.businessName} 
                className="occupied-logo" 
              />
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdGrid;
